    // 注意：根据要求，指针长度必须严格对应内存大小
    printf("[测试 3] 模拟极大长度 (探测内存分配逻辑)...\n");
    size_t huge_size = 0xFFFFFFFF; // 4GB (在32位系统下为满额，64位系统下为大值)
    unsigned char *huge_data = malloc(huge_size);
