        firmware_update_process(huge_data, huge_size, normal_version);
        free(huge_data);
    } else {
        printf("[测试 3] 跳过：无法分配足够内存进行极大长度测试\n");
    }

    // --- 测试用例 4: 超长版本字符串 (Buffer Overflow) ---
    printf("[测试 4] 超长版本号字符串...\n");
